public String[] fizzBuzz(int start, int end)
{
    end--;
    String[] result = new String[end - start];

    for (int i = 0; i < end; i++)
    {
        if ((i + 1) % 15 == 0 && i > 0)
        {
            result[i] = "FizzBuzz";
        }
        else if ((i + 1) % 3 == 0 && i > 0)
        {
            result[i] = "Fizz";
        }
        else if ((i + 1) % 5 == 0 && i > 0)
        {
            result[i] = "Buzz";
        }
        else {
            result[i] = String.valueOf(i + start);
        }
    }

    return result;
}

